import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { StoreReportsComponent } from './store-reports/store-reports.component';
import { StoreTransactionsReportsComponent } from './store-transactions-reports/store-transactions-reports.component';
import { TransactionsReportsComponent } from './transactions-reports/transactions-reports.component';
import { UserReportsComponent } from './user-reports/user-reports.component';

const routes: Routes = [
  {path: 'user', component: UserReportsComponent},
  {path: 'stores', component: StoreReportsComponent},
  {path: 'store/transactions', component: StoreTransactionsReportsComponent},
  {path: 'transactions', component: TransactionsReportsComponent},
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class ReportsRoutingModule { }
