import { Component } from '@angular/core';
import { Form, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ApiService } from '@services/api.service';
import {Country, State} from 'country-state-city';
import moment from 'moment';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';
@Component({
  selector: 'app-store-reports',
  templateUrl: './store-reports.component.html',
  styleUrls: ['./store-reports.component.scss']
})
export class StoreReportsComponent {
  countries: any[];
  states: any[];
  isLoading = false;

  form: FormGroup;

  constructor(
    private fb: FormBuilder,
    private api: ApiService,
    private toastr: ToastrService
  ) {

    this.form = this.fb.group({
      country: [null],
      state: [null],
      from_date: [ moment().startOf('month').toDate() , [Validators.required]],
      to_date: [moment().toDate(), [Validators.required]],
    })

    this.countries = Country.getAllCountries();
    this.form.controls.country.valueChanges.subscribe((countryName) => {
      const country = Country.getAllCountries().find((__c) => __c.name == countryName )
      const states = State.getStatesOfCountry(country.isoCode);
      console.log(states)
      this.states = states;
    })
  }

  generateReport() {
    this.isLoading = true;

    const country = this.form.value.country ? {country: this.form.value.country} : {};
    const state = this.form.value.state ? {state: this.form.value.state} : {};
    const from_date = moment(this.form.value.from_date).format('yyyy-MM-DD')
    const to_date = moment(this.form.value.to_date).format('yyyy-MM-DD')

    const sub = this.api.generateStoreReports({from_date, to_date, ...country, ...state})
    .pipe(
      catchError(err => err)
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success( response.message )
    })
  }

}
