import { Component } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { ApiService } from '@services/api.service';
import { Country, State } from 'country-state-city';
import moment from 'moment';
import { ToastrService } from 'ngx-toastr';
import { catchError, debounceTime, tap } from 'rxjs';

@Component({
  selector: 'app-store-transactions-reports',
  templateUrl: './store-transactions-reports.component.html',
  styleUrls: ['./store-transactions-reports.component.scss']
})
export class StoreTransactionsReportsComponent {
  countries: any[];
  states: any[];
  isLoading = false;

  form: FormGroup;
  storeForm: FormGroup;

  stores: any[] = []
  selectedStores: any[] = [];


  constructor(
    private fb: FormBuilder,
    private api: ApiService,
    private toastr: ToastrService
  ) {

    this.form = this.fb.group({
      from_date: [ moment().startOf('month').toDate() , [Validators.required]],
      to_date: [moment().toDate(), [Validators.required]],
    })

    this.storeForm = this.fb.group({
      store_name: ['',]
    })

    this.storeForm.valueChanges.pipe(
      debounceTime(500),
      tap(() => {
        this.listStores(this.storeForm.value.store_name);
      })
    ).subscribe();

    this.listStores(this.storeForm.value.store_name);
  }

  listStores(q: string) {
    const sub = this.api.listStores(q, 1, 100, 'store_id', 'DESC').subscribe((response: any) => {
      sub.unsubscribe()
      this.stores = response.stores.map(({store_name, store_id}) => {
        return {store_name, store_id}
      })
    })
  }

  generateReport() {
    this.isLoading = true;

    const from_date = moment(this.form.value.from_date).format('yyyy-MM-DD')
    const to_date = moment(this.form.value.to_date).format('yyyy-MM-DD')

    const sub = this.api.generateTransactionReport({from: from_date,to: to_date, stores: this.selectedStores})
    .pipe(
      catchError(err => err)
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success( response.message )
    })
  }

  addStore(store: any) {
    if(!this.selectedStores.find(s => s.store_id == store.store_id))
      this.selectedStores.push(store)
  }

  removeStore(store: any) {
    this.selectedStores = this.selectedStores.filter((s) => s.store_id != store.store_id)
  }

  getStoreInSelectedStore(store_id): boolean {
    return this.selectedStores.find((s) => s.store_id == store_id) ? true : false;
  }

}
